mapper.select:
{ CALL GET_CREDIT_SUMMARY(
  #{studentId, mode=IN, jdbcType=VARCHAR},
  #{applied, mode=OUT, jdbcType=NUMERIC},
  #{max, mode=OUT, jdbcType=NUMERIC},
  #{courseCount, mode=OUT, jdbcType=NUMERIC},
  #{cartCount, mode=OUT, jdbcType=NUMERIC}
) }

SELECT
  (SELECT COUNT(*) FROM cart_item ci WHERE ci.s_id = #{studentId}) AS cart_count,
  (
    SELECT COUNT(*)
    FROM enroll e
    LEFT JOIN review r ON r.e_id = e.e_id
    WHERE e.s_id = #{studentId}
      AND e.e_year = #{year}
      AND e.e_semester = #{semester}
      AND e.e_status IN ('ENROLLED', 'COMPLETED')
      AND r.review_id IS NULL
  ) AS review_pending_count
FROM dual
